import { ZuploContext, ZuploRequest, ZuploMcpSdk } from "@zuplo/runtime";

const customers = {
  "123": "Customer 123 is a premium member from New York.",
  "456": "Customer 456 is a standard member from London."
};

export default async function (request: ZuploRequest, context: ZuploContext) {
  const mcp = new ZuploMcpSdk(context);
  const mcpRequest = mcp.getRawCallToolRequest();

  if (!mcpRequest) {
    return new Response("Not an MCP request", { status: 400 });
  }

  const { customerId } = mcpRequest.params.arguments as { customerId: string };
  const summary = customers[customerId] || "Customer not found.";

  return {
    content: [
      {
        type: "text",
        text: summary
      }
    ]
  };
}

